(window.webpackJsonp=window.webpackJsonp||[]).push([[808],{795:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">target</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">n</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{string[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> buildArray = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">target, n</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> res=[]\\n  <span class=\\"hljs-keyword\\">let</span> x=<span class=\\"hljs-number\\">1</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;target.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(target[i]!==x){\\n      res.push(<span class=\\"hljs-string\\">\'Push\'</span>,<span class=\\"hljs-string\\">\'Pop\'</span>)\\n      i--\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      res.push(<span class=\\"hljs-string\\">\'Push\'</span>)\\n    }\\n    x++\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"build-an-array-with-stack-operations","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u76ee\u6807\u6570\u7ec4 <code>target</code> \u548c\u4e00\u4e2a\u6574\u6570 <code>n</code>\u3002\u6bcf\u6b21\u8fed\u4ee3\uff0c\u9700\u8981\u4ece\xa0 <code>list = {1,2,3..., n}</code> \u4e2d\u4f9d\u5e8f\u8bfb\u53d6\u4e00\u4e2a\u6570\u5b57\u3002</p>\\n\\n<p>\u8bf7\u4f7f\u7528\u4e0b\u8ff0\u64cd\u4f5c\u6765\u6784\u5efa\u76ee\u6807\u6570\u7ec4 <code>target</code> \uff1a</p>\\n\\n<ul>\\n\\t<li><strong>Push</strong>\uff1a\u4ece <code>list</code> \u4e2d\u8bfb\u53d6\u4e00\u4e2a\u65b0\u5143\u7d20\uff0c \u5e76\u5c06\u5176\u63a8\u5165\u6570\u7ec4\u4e2d\u3002</li>\\n\\t<li><strong>Pop</strong>\uff1a\u5220\u9664\u6570\u7ec4\u4e2d\u7684\u6700\u540e\u4e00\u4e2a\u5143\u7d20\u3002</li>\\n\\t<li>\u5982\u679c\u76ee\u6807\u6570\u7ec4\u6784\u5efa\u5b8c\u6210\uff0c\u5c31\u505c\u6b62\u8bfb\u53d6\u66f4\u591a\u5143\u7d20\u3002</li>\\n</ul>\\n\\n<p>\u9898\u76ee\u6570\u636e\u4fdd\u8bc1\u76ee\u6807\u6570\u7ec4\u4e25\u683c\u9012\u589e\uff0c\u5e76\u4e14\u53ea\u5305\u542b <code>1</code> \u5230 <code>n</code> \u4e4b\u95f4\u7684\u6570\u5b57\u3002</p>\\n\\n<p>\u8bf7\u8fd4\u56de\u6784\u5efa\u76ee\u6807\u6570\u7ec4\u6240\u7528\u7684\u64cd\u4f5c\u5e8f\u5217\u3002</p>\\n\\n<p>\u9898\u76ee\u6570\u636e\u4fdd\u8bc1\u7b54\u6848\u662f\u552f\u4e00\u7684\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>target = [1,3], n = 3\\n<strong>\u8f93\u51fa\uff1a</strong>[\\"Push\\",\\"Push\\",\\"Pop\\",\\"Push\\"]\\n<strong>\u89e3\u91ca\uff1a \\n</strong>\u8bfb\u53d6 1 \u5e76\u81ea\u52a8\u63a8\u5165\u6570\u7ec4 -> [1]\\n\u8bfb\u53d6 2 \u5e76\u81ea\u52a8\u63a8\u5165\u6570\u7ec4\uff0c\u7136\u540e\u5220\u9664\u5b83 -> [1]\\n\u8bfb\u53d6 3 \u5e76\u81ea\u52a8\u63a8\u5165\u6570\u7ec4 -> [1,3]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>target = [1,2,3], n = 3\\n<strong>\u8f93\u51fa\uff1a</strong>[\\"Push\\",\\"Push\\",\\"Push\\"]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>target = [1,2], n = 4\\n<strong>\u8f93\u51fa\uff1a</strong>[\\"Push\\",\\"Push\\"]\\n<strong>\u89e3\u91ca\uff1a</strong>\u53ea\u9700\u8981\u8bfb\u53d6\u524d 2 \u4e2a\u6570\u5b57\u5c31\u53ef\u4ee5\u505c\u6b62\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>target = [2,3,4], n = 4\\n<strong>\u8f93\u51fa\uff1a</strong>[\\"Push\\",\\"Pop\\",\\"Push\\",\\"Push\\",\\"Push\\"]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= target.length <= 100</code></li>\\n\\t<li><code>1 <= target[i]\xa0<= 100</code></li>\\n\\t<li><code>1 <= n <= 100</code></li>\\n\\t<li><code>target</code> \u662f\u4e25\u683c\u9012\u589e\u7684</li>\\n</ul>\\n","title":"1441. \u7528\u6808\u64cd\u4f5c\u6784\u5efa\u6570\u7ec4","relatedTags":["\u6808"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1441"}')}}]);